import sailpoint.object.Filter;
import sailpoint.object.Bundle;
import sailpoint.object.QueryOptions;
import java.util.Calendar;
import org.apache.commons.lang3.StringUtils;
import java.util.Date;

String org;
String company;
String dept;
String ent;
String userIdentity;
if(args.get("Organization") != null){
org=args.get("Organization");
}
if (org != null){

if(StringUtils.isNotBlank(org) @and org.equals("IFC")){
company = "0";
}else if(StringUtils.isNotBlank(org) @and org.equals("IBRD")){
company = "1";
}
else if(StringUtils.isNotBlank(org) @and org.equals("MIGA")){
company = "2";
}
else if(StringUtils.isNotBlank(org) @and org.equals("GEF")){
company = "5";
}

}
if(args.get("Unit") != null){
dept=args.get("Unit");
}

query=query + " where application in (select id from Application where name='SAP') and aggregationState='Connected'";
if(company != null ){
query=query + " and identity in (select id from Identity where extended1='"+company+"')";
}
if(dept != null){
query=query + " and identity in (select id from Identity where extended7='"+dept+"')";
}

if(args.get("entitlement") != null){
ent=args.get("entitlement");
}

if(ent != null) {
query=query + " and value='"+ent+"'";
}  
if(args.get("identity") != null){
userIdentity=args.get("identity");
}

if(userIdentity != null) {
query=query + " and identity ='"+userIdentity+"'";
}  

return query;

