import java.util.Date;
import java.util.List;
import java.text.SimpleDateFormat;
import org.apache.commons.logging.Log;
import sailpoint.object.Bundle;
import sailpoint.object.Identity;
import sailpoint.tools.Util;
import sailpoint.object.RoleAssignment;
import sailpoint.tools.GeneralException;

Date endDate = null;
String endstr = null;
try {
if(null != value){
Identity identityObj = value;
if(identityObj != null){
if(identityObj.getPreferences() != null @and identityObj.getPreferences().size() > 0) {

List<RoleAssignment> roleAssignments = (List) identityObj.getActiveRoleAssignments(scriptArgs.get("attributes.sourceAssignableRoles"));
if(roleAssignments != null @and roleAssignments.size() > 0){
for(RoleAssignment roleAssignment : roleAssignments) {
if(roleAssignment.getEndDate() != null)
{
endDate = roleAssignment.getEndDate();
log.debug("==before formate =endDate==="+endDate);
SimpleDateFormat sdf=new SimpleDateFormat("MM/dd/yyyy h:mm a");
log.debug("+++sdf++"+sdf);
endstr = sdf.format(endDate);
log.debug("+++endstr++"+endstr);
log.debug("==Post formate =endDate==="+endstr);
}  
}
 return endstr;
}
}
}
}
} catch (GeneralException e) {

log.error("GeneralException : " + e.getMessage());

}
